class StepRange:
    def __init__(self, start, stop, step=1):
        self.current = start
        self.stop = stop
        self.step = step

    def __iter__(self):
        return self

    def __next__(self):
        if self.current >= self.stop:
            raise StopIteration
        value = self.current
        self.current += self.step
        return value

# Usage: for i in StepRange(0, 10, 2): print(i)

class ValidatedProperty:
    def __init__(self, validator, error_msg='Invalid value'):
        self.validator = validator
        self.error_msg = error_msg

    def __set_name__(self, owner, name):
        self.name = '_' + name

    def __get__(self, obj, objtype=None):
        return getattr(obj, self.name, None)

    def __set__(self, obj, value):
        if not self.validator(value):
            raise ValueError(self.error_msg)
        setattr(obj, self.name, value)

class User:
    age = ValidatedProperty(lambda x: isinstance(x, int) and 0 < x < 150, 'Age must be 1-149')
    email = ValidatedProperty(lambda x: '@' in x, 'Invalid email')

import functools

def singleton(cls):
    instances = {}

    @functools.wraps(cls)
    def get_instance(*args, **kwargs):
        if cls not in instances:
            instances[cls] = cls(*args, **kwargs)
        return instances[cls]

    return get_instance

@singleton
class Database:
    def __init__(self, url):
        self.url = url

